```class Solution {
public:
    int maxPalindromes(string s, int k) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + k; j <= n; j++) {
                string t = s.substr(i, j - i);
                if (t == reverse(t) && j - i >= k) {
                    res++;
                    i = j;
                    break;
                }
            }
        }
        return res;
    }
};
